import { useEffect, useState, useRef } from 'react'
import { useNavigate, useSearchParams } from 'react-router-dom'
import { useAuthKR } from '@/shared/stores/useAuthKR'
import { useAuthWorld } from '@/shared/stores/useAuthWorld'
import { isKorea } from '@/shared/config/region'
import { signInWithCustomToken } from 'firebase/auth'
import { auth } from '@/lib/firebase'
import { UserInfo } from '@/components/my-page/user-info'
import { MenuList } from '@/components/my-page/menu-list'
import { LogoutButton } from '@/components/my-page/logout-button'
import { Footer } from '@/components/my-page/footer'
import BottomNav from '@/components/main/BottomNav'
import { ArrowLeft } from 'lucide-react'

export default function UserProfilePage() {
  const navigate = useNavigate()
  const [searchParams] = useSearchParams()
  
  // вЬЕ Zustand мК§нЖ†мЦі мВђмЪ© (мІАмЧ≠л≥Д)
  const authStore = isKorea() ? useAuthKR : useAuthWorld
  const { user, isAuthReady, logout: authLogout } = authStore()
  const isLoggedIn = !!user
  
  const [userName, setUserName] = useState('')
  const [isProcessingToken, setIsProcessingToken] = useState(false)
  const hasProcessedToken = useRef(false)

  // вЬЕ firebase_token к∞Хм†Ь м≤Шл¶ђ л°ЬмІБ
  useEffect(() => {
    const firebaseToken = searchParams.get('firebase_token')
    
    // нЖ†нБ∞мЭі мЮИк≥†, мХДмІБ м≤Шл¶ђ мХИ нЦИк≥†, мЭЄм¶Э м§АлєДлР®
    if (firebaseToken && !hasProcessedToken.current && isAuthReady) {
      hasProcessedToken.current = true
      setIsProcessingToken(true)
      
      console.log('[UserProfilePage] рЯФС firebase_token л∞Ьк≤ђ - мЮРлПЩ л°ЬкЈЄмЭЄ м≤Шл¶ђ')
      
      signInWithCustomToken(auth, firebaseToken)
        .then((credential) => {
          console.log('[UserProfilePage] вЬЕ Firebase л°ЬкЈЄмЭЄ мД±к≥µ')
          
          // рЯФ• л∞±кЈЄлЭЉмЪілУЬмЧРмДЬ нЖ†нБ∞ к∞±мЛ† (await мЧЖмЭі лєДлПЩкЄ∞ мЛ§нЦЙ)
          credential.user.getIdToken(true)
            .then(() => console.log('[UserProfilePage] рЯФ• ID Token к∞Хм†Ь к∞±мЛ† мЩДл£М (л∞±кЈЄлЭЉмЪілУЬ)'))
            .catch((err) => console.warn('[UserProfilePage] вЪ†пЄП Token к∞±мЛ† мЛ§нМ® (лђімЛЬ):', err))
          
          // вЬЕ React RouterмЭШ navigateл°Ь URL м†Хл¶ђ (лђінХЬ л£®нФД л∞©мІА)
          console.log('[UserProfilePage] рЯІє URL м†Хл¶ђ м§С (firebase_token м†Ьк±∞)...')
          setIsProcessingToken(false)
          
          // navigateл•Љ мВђмЪ©нХі React Routerк∞А мЭЄмЛЭнХШлПДл°Э нХ®
          navigate('/user/profile', { replace: true })
          console.log('[UserProfilePage] вЬЕ URL м†Хл¶ђ мЩДл£М')
        })
        .catch((error) => {
          console.error('[UserProfilePage] вЭМ Firebase л°ЬкЈЄмЭЄ мЛ§нМ®:', error)
          hasProcessedToken.current = false // мЛ§нМ® мЛЬ мЮђмЛЬлПД нЧИмЪ©
          setIsProcessingToken(false)
          navigate('/login', { replace: true })
        })
      
      return
    }
  }, [searchParams, isAuthReady, navigate])

  useEffect(() => {
    // вЬЕ нЖ†нБ∞ м≤Шл¶ђ м§СмЧРлКФ лМАкЄ∞
    if (isProcessingToken) {
      console.log('[UserProfilePage] вП≥ нЖ†нБ∞ м≤Шл¶ђ м§С...')
      return
    }

    // вЬЕ 1. isAuthReady к∞АлУЬ: мЭЄм¶Э міИкЄ∞нЩФ м†ДмЧРлКФ лМАкЄ∞
    if (!isAuthReady) {
      console.log('[UserProfilePage] вП≥ мЭЄм¶Э міИкЄ∞нЩФ лМАкЄ∞ м§С...')
      return
    }

    // вЬЕ 2. л°ЬкЈЄмЭЄ м≤інБђ: isAuthReady нЫДмЧРлІМ мЛ§нЦЙ
    if (!isLoggedIn) {
      // firebase_tokenмЭі мЮИмЬЉл©і л¶ђлЛ§мЭіл†ЙнКЄ мІАмЧ∞
      const firebaseToken = searchParams.get('firebase_token')
      if (firebaseToken) {
        console.log('[UserProfilePage] вП≥ firebase_token мЮИмЭМ - л°ЬкЈЄмЭЄ м≤Шл¶ђ лМАкЄ∞ м§С...')
        return
      }
      
      console.log('[UserProfilePage] вЭМ л°ЬкЈЄмЭЄ нХДмЪФ - /loginмЬЉл°Ь л¶ђлЛ§мЭіл†ЙнКЄ')
      // рЯОѓ мК§лІИнКЄ л¶ђлЛ§мЭіл†ЙнКЄ: нШДмЮђ нОШмЭімІАл•Љ returnUrlл°Ь м†АмЮ•
      sessionStorage.setItem('returnUrl', '/user/profile')
      navigate('/login', { replace: true })
      return
    }

    // вЬЕ 3. Firebase UserмЧРмДЬ мВђмЪ©мЮР мЭіл¶Д к∞Ам†ЄмШ§кЄ∞ (Single Source of Truth)
    // displayNameмЭі мЧЖмЬЉл©і localStorageмЭШ user_name мВђмЪ© (мєімєімШ§ л°ЬкЈЄмЭЄ мЛЬ м†АмЮ•лР®)
    const name = user?.displayName || localStorage.getItem('user_name') || 'мВђмЪ©мЮР'
    setUserName(name)
    
    console.log('[UserProfilePage] вЬЕ мВђмЪ©мЮР м†Хл≥і л°ЬлУЬ:', {
      uid: user?.uid,
      displayName: user?.displayName,
      email: user?.email,
      userName: name,
      isLoggedIn
    })
  }, [isAuthReady, isLoggedIn, user, navigate, searchParams, isProcessingToken])

  const handleLogout = async () => {
    console.log('[UserProfilePage] л°ЬкЈЄмХДмЫГ м≤Шл¶ђ')
    
    try {
      // вЬЕ AuthContextмЭШ logout мВђмЪ© (Firebase + localStorage л™®лСР м≤Шл¶ђ)
      await authLogout()
      
      console.log('[UserProfilePage] вЬЕ л°ЬкЈЄмХДмЫГ мЩДл£М')
      // нЩИнОШмЭімІАл°Ь л¶ђлЛ§мЭіл†ЙнКЄ
      navigate('/')
    } catch (error) {
      console.error('[UserProfilePage] вЭМ л°ЬкЈЄмХДмЫГ мЛ§нМ®:', error)
    }
  }

  // вЬЕ 4. нЖ†нБ∞ м≤Шл¶ђ м§С лШРлКФ isAuthReady м†ДмЧРлКФ л°ЬлФ© нСЬмЛЬ
  if (isProcessingToken || !isAuthReady) {
    return (
      <div className="min-h-screen bg-background flex items-center justify-center">
        <div className="text-center">
          <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-[#ff6b35] mx-auto mb-4"></div>
          <p className="text-gray-600">{isProcessingToken ? 'л°ЬкЈЄмЭЄ м≤Шл¶ђ м§С...' : 'л°ЬлФ© м§С...'}</p>
        </div>
      </div>
    )
  }

  // вЬЕ 5. л°ЬкЈЄмЭЄ мХИ лР®: л¶ђлЛ§мЭіл†ЙнКЄ м§С
  if (!isLoggedIn) {
    return null
  }

  return (
    <div className="min-h-screen bg-background flex flex-col">
      {/* Header with Back Button */}
      <div className="sticky top-0 z-50 bg-white border-b border-gray-200">
        <div className="flex items-center px-4 py-3">
          <button
            onClick={() => navigate('/')}
            className="flex items-center justify-center w-10 h-10 rounded-full hover:bg-gray-100 transition-colors"
            aria-label="лТ§л°Ьк∞АкЄ∞"
          >
            <ArrowLeft className="w-5 h-5" />
          </button>
          <h1 className="flex-1 text-center text-[18px] font-bold pr-10">лІИмЭінОШмЭімІА</h1>
        </div>
      </div>

      {/* User Info Section */}
      <UserInfo userName={userName} />

      {/* Menu List Section */}
      <MenuList />

      {/* Logout Button Section */}
      <div className="px-5 py-6">
        <button 
          onClick={handleLogout}
          className="flex w-full items-center justify-center gap-2 rounded-xl border border-border bg-background py-3.5 text-sm font-medium text-muted-foreground transition-colors active:bg-secondary"
        >
          <svg className="h-4 w-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M17 16l4-4m0 0l-4-4m4 4H7m6 4v1a3 3 0 01-3 3H6a3 3 0 01-3-3V7a3 3 0 013-3h4a3 3 0 013 3v1" />
          </svg>
          л°ЬкЈЄмХДмЫГ
        </button>
      </div>

      {/* Footer Section */}
      <Footer />
      
      {/* Bottom Navigation Spacer */}
      <div className="h-20" aria-hidden="true"></div>
      
      {/* Bottom Navigation */}
      <BottomNav />
    </div>
  )
}
